const tbodyEl = document.querySelector(".list");
const getStudentsBtnEl = document.getElementById("get-students-btn");
const studentsTable = document.getElementById("students-table");
const addStudentForm = document.getElementById("add-student-form");

let currentId = null;

// Функція для отримання всіх студентів

getStudentsBtnEl.addEventListener("click", () => {
    const res = getStudents();
    renderStudents(res);
        
    studentsTable.style.display = "table";

})

function getStudents() {

    const res = fetch("http://localhost:3000/students");
    const info = res.json();
    return info;
}



// Функція для відображення студентів у таблиці

function renderStudents(students) {

    const item = students.map(({id, name, age, course, skills, email, isEnrolled}) => {
        return `<tr id="${id}">
                    <td>${id}</td>
                    <td>${name}</td>
                    <td>${age}</td>
                    <td>${course}</td>
                    <td>${skills}</td>
                    <td>${email}</td>
                    <td>${isEnrolled ? "Навчається" : "Не навчається"}</td>
                    <td>
                        <button data-action="edit" type="button">Edit</button>
                        <button data-action="delete" type="button">Delete</button>
                    </td>
                </tr>`
    }).join("");
    tbodyEl.innerHTML = item;
}


addStudentForm.addEventListener("submit", (e) => {
    e.preventDefault();

    const data = {
        name: e.currentTarget.elements.name.value,
        age: e.currentTarget.elements.age.value,
        course: e.currentTarget.elements.course.value,
        skills: e.currentTarget.elements.skills.value,
        email: e.currentTarget.elements.email.value,
        isEnrolled: e.currentTarget.elements.isEnrolled.checked
    };
    if(currentId) {

            updateStudent(currentId, data);
            const res = getStudents();
            renderStudents(res);

            addStudentForm.reset();
            currentId = null;
            return;

    }

        addStudent(data);
        const res = getStudents();
        renderStudents(res);

        addStudentForm.reset();

});


// Функція для додавання нового студента

function addStudent(e) {
    const options = {
        method: "POST",
        body: JSON.stringify(e),
        headers: {
            "Content-Type": "application/json; charset=UTF-8"
        },
    }
    const res = fetch("http://localhost:3000/students", options);
    const info = res.json();
    return info;
}



// Функція для оновлення студента

function updateStudent(id, data) {

    const options = {
        method: "PUT",
        body: JSON.stringify(data),
        headers: {
            "Content-Type": "application/json; charset=UTF-8"
        },
    }

    const res = fetch(`http://localhost:3000/students/${id}`, options);

    const response = res.json();
    return response;


 }



// Функція для видалення студента

function deleteStudent(id) {

        const res = fetch(`http://localhost:3000/students/${id}`,{
        method: "DELETE"
    })


    const info = res.json();
    return;

}

tbodyEl.addEventListener("click", async (e) => {
    const td = e.target.closest("tr");
    const row = td.parentNode;
    const id = row.id;

    // const row = e.target.closest("tr");

    // if (!row) {
    //     return
    // }
    // const id = row.id;

    if(e.target.dataset.action === "delete") {
            deleteStudent(id);
            const res = getStudents();
            renderStudents(res);
    }

    if(e.target.dataset.action === "edit") {
        currentId = id;

        addStudentForm.elements[0].value = row.children[1].textContent; // ім'я
        addStudentForm.elements[1].value = row.children[2].textContent; // вік
        addStudentForm.elements[2].value = row.children[3].textContent; // курс
        addStudentForm.elements[3].value = row.children[4].textContent; // навички
        addStudentForm.elements[4].value = row.children[5].textContent; // email
        addStudentForm.elements[5].checked = row.children[6].textContent === "Навчається";
    }
})